"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { getRandomComplete } from "@/lib/learningMessages";

// ===== 数据：12 个水果，打乱顺序展示 =====
// 苹果×3、香蕉×3、葡萄×2、橘子×4
const SCRAMBLED: string[] = [
  "🍎", "🍊", "🍌", "🍇", "🍊", "🍎", "🍊", "🍌", "🍇", "🍊", "🍎", "🍌",
];

// 水果 -> 颜色映射（红黄紫橙）
const FRUIT_COLOR: Record<string, string> = {
  "🍎": "var(--accent)", // 红
  "🍌": "var(--accent3)", // 黄
  "🍇": "#A78BFA", // 紫
  "🍊": "var(--signal-shake)", // 橙
};

function colorOf(emoji: string): string {
  return FRUIT_COLOR[emoji] ?? "var(--primary)";
}

// ===== 分类配置 =====
interface Category {
  title: string;
  emoji: string;
  count: number;
  color: string;
}

// 按种类分
const TYPE_GROUPS: Category[] = [
  { title: "苹果", emoji: "🍎", count: 3, color: "var(--accent)" },
  { title: "香蕉", emoji: "🍌", count: 3, color: "var(--accent3)" },
  { title: "葡萄", emoji: "🍇", count: 2, color: "#A78BFA" },
  { title: "橘子", emoji: "🍊", count: 4, color: "var(--signal-shake)" },
];

// 按颜色分（与水果一一对应：红=苹果、黄=香蕉、紫=葡萄、橙=橘子）
const COLOR_GROUPS: Category[] = [
  { title: "红色", emoji: "🍎", count: 3, color: "var(--accent)" },
  { title: "黄色", emoji: "🍌", count: 3, color: "var(--accent3)" },
  { title: "紫色", emoji: "🍇", count: 2, color: "#A78BFA" },
  { title: "橙色", emoji: "🍊", count: 4, color: "var(--signal-shake)" },
];

// ===== 物品池 =====
function ItemPool() {
  return (
    <div className="flex flex-wrap justify-center gap-2">
      {SCRAMBLED.map((emoji, i) => (
        <div
          key={i}
          className="flex h-12 w-12 items-center justify-center rounded-xl text-2xl shadow-[var(--shadow-sm)] animate-float-in"
          style={{
            backgroundColor: "var(--bg-card)",
            border: `2px solid ${colorOf(emoji)}`,
          }}
        >
          {emoji}
        </div>
      ))}
    </div>
  );
}

// ===== 分类框 =====
function CategoryBox({
  group,
  sorted,
}: {
  group: Category;
  sorted: boolean;
}) {
  return (
    <div
      className="flex min-h-[116px] flex-col rounded-xl border-2 p-3 transition-all duration-300"
      style={{
        borderColor: sorted ? group.color : "var(--signal-pending)",
        backgroundColor: sorted
          ? `color-mix(in srgb, ${group.color} 8%, transparent)`
          : "var(--bg-card)",
      }}
    >
      <div className="mb-2 flex items-center justify-between">
        <span className="flex items-center gap-1 text-sm font-bold text-[var(--text)]">
          <span className="text-lg">{group.emoji}</span>
          {group.title}
        </span>
        {sorted ? (
          <span
            className="rounded-full px-2 py-0.5 text-xs font-bold text-white"
            style={{ backgroundColor: group.color }}
          >
            {group.count} 个
          </span>
        ) : (
          <span className="text-xs text-[var(--text-muted)]">?</span>
        )}
      </div>
      <div className="flex flex-wrap gap-1">
        {sorted ? (
          Array.from({ length: group.count }).map((_, i) => (
            <div
              key={i}
              className="flex h-9 w-9 items-center justify-center rounded-lg text-xl animate-float-in"
              style={{
                backgroundColor: `color-mix(in srgb, ${group.color} 18%, transparent)`,
                border: `1.5px solid ${group.color}`,
              }}
            >
              {group.emoji}
            </div>
          ))
        ) : (
          <span className="text-xs italic text-[var(--text-muted)]">
            等待分类…
          </span>
        )}
      </div>
    </div>
  );
}

// ===== 主组件 =====
type Phase = "byType" | "byColor" | "compare" | "done";

export default function TransformPage() {
  const [phase, setPhase] = useState<Phase>("byType");
  const [typeSorted, setTypeSorted] = useState(false);
  const [colorSorted, setColorSorted] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const nextStep = getNextStep("data", "transform");

  const resetAll = () => {
    setPhase("byType");
    setTypeSorted(false);
    setColorSorted(false);
  };

  return (
    <StepShell topicId="data" stepId="transform">
      <div className="space-y-6">
        {/* 情境说明 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
          <p className="text-[var(--text)]">
            🔄 同样一些水果，换个分类方式，结果会变吗？
          </p>
          <p className="mt-1 text-sm text-[var(--text-secondary)]">
            一共 12 个水果，先按种类分，再按颜色分，比一比结果！
          </p>
        </div>

        {/* ===== 阶段 1：按种类分 ===== */}
        {phase === "byType" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--accent)]">
                阶段 1 / 2
              </p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                按种类分
              </h2>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                下面有 12 个水果，点一点把它们按种类分开
              </p>
            </div>

            {/* 物品池 */}
            <div className="mt-5 rounded-xl bg-[var(--bg-soft)] p-4">
              <p className="mb-2 text-center text-xs text-[var(--text-muted)]">
                一共有 {SCRAMBLED.length} 个水果
              </p>
              <ItemPool />
            </div>

            {/* 分类框 */}
            <div className="mt-5 grid grid-cols-2 gap-3">
              {TYPE_GROUPS.map((g) => (
                <CategoryBox key={g.title} group={g} sorted={typeSorted} />
              ))}
            </div>

            {/* 操作区 */}
            <div className="mt-5 flex flex-col items-center gap-3">
              {!typeSorted ? (
                <button
                  onClick={() => setTypeSorted(true)}
                  className="rounded-full bg-[var(--accent)] px-8 py-3 font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  按种类分一分 →
                </button>
              ) : (
                <div className="flex flex-col items-center gap-3 animate-float-in">
                  <p className="text-sm font-medium text-[var(--signal-success)]">
                    ✓ 按种类分好了：苹果 3、香蕉 3、葡萄 2、橘子 4
                  </p>
                  <button
                    onClick={() => setPhase("byColor")}
                    className="rounded-full bg-[var(--accent)] px-6 py-3 font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  >
                    换个方式：按颜色分 →
                  </button>
                </div>
              )}
            </div>
          </section>
        )}

        {/* ===== 阶段 2：按颜色分 ===== */}
        {phase === "byColor" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--primary)]">
                阶段 2 / 2
              </p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                按颜色分
              </h2>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                还是这 12 个水果，这次按颜色重新分一分
              </p>
            </div>

            {/* 物品池 */}
            <div className="mt-5 rounded-xl bg-[var(--bg-soft)] p-4">
              <p className="mb-2 text-center text-xs text-[var(--text-muted)]">
                还是这 {SCRAMBLED.length} 个水果
              </p>
              <ItemPool />
            </div>

            {/* 分类框 */}
            <div className="mt-5 grid grid-cols-2 gap-3">
              {COLOR_GROUPS.map((g) => (
                <CategoryBox key={g.title} group={g} sorted={colorSorted} />
              ))}
            </div>

            {/* 操作区 */}
            <div className="mt-5 flex flex-col items-center gap-3">
              {!colorSorted ? (
                <button
                  onClick={() => setColorSorted(true)}
                  className="rounded-full bg-[var(--primary)] px-8 py-3 font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105"
                >
                  按颜色分一分 →
                </button>
              ) : (
                <div className="flex flex-col items-center gap-3 animate-float-in">
                  <p className="text-sm font-medium text-[var(--signal-success)]">
                    ✓ 按颜色分好了：红 3、黄 3、紫 2、橙 4
                  </p>
                  <button
                    onClick={() => setPhase("compare")}
                    className="rounded-full bg-[var(--primary)] px-6 py-3 font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105"
                  >
                    对比两种分法 →
                  </button>
                </div>
              )}
            </div>
          </section>
        )}

        {/* ===== 对比总结 ===== */}
        {phase === "compare" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <h2 className="text-xl font-bold text-[var(--text)]">
                对比两种分类
              </h2>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                比一比，两种分法的结果一样吗？
              </p>
            </div>

            <div className="mt-5 grid gap-4 md:grid-cols-2">
              {/* 按种类分 */}
              <div className="rounded-xl border-2 border-[var(--accent)] bg-[var(--accent)]/5 p-4">
                <p className="mb-3 text-center text-sm font-bold text-[var(--accent)]">
                  按种类分
                </p>
                <div className="space-y-2">
                  {TYPE_GROUPS.map((g) => (
                    <div
                      key={g.title}
                      className="flex items-center justify-between rounded-lg bg-[var(--bg-card)] px-3 py-2"
                    >
                      <span className="flex items-center gap-1 text-sm text-[var(--text)]">
                        <span className="text-lg">{g.emoji}</span>
                        {g.title}
                      </span>
                      <span
                        className="rounded-full px-2 py-0.5 text-xs font-bold text-white"
                        style={{ backgroundColor: g.color }}
                      >
                        {g.count}
                      </span>
                    </div>
                  ))}
                </div>
                <p className="mt-3 text-center text-xs text-[var(--text-muted)]">
                  总数：3 + 3 + 2 + 4 ={" "}
                  <strong className="text-[var(--text)]">12</strong>
                </p>
              </div>

              {/* 按颜色分 */}
              <div className="rounded-xl border-2 border-[var(--primary)] bg-[var(--primary)]/5 p-4">
                <p className="mb-3 text-center text-sm font-bold text-[var(--primary)]">
                  按颜色分
                </p>
                <div className="space-y-2">
                  {COLOR_GROUPS.map((g) => (
                    <div
                      key={g.title}
                      className="flex items-center justify-between rounded-lg bg-[var(--bg-card)] px-3 py-2"
                    >
                      <span className="flex items-center gap-2 text-sm text-[var(--text)]">
                        <span
                          className="inline-block h-3 w-3 rounded-full"
                          style={{ backgroundColor: g.color }}
                        />
                        {g.title}
                      </span>
                      <span
                        className="rounded-full px-2 py-0.5 text-xs font-bold text-white"
                        style={{ backgroundColor: g.color }}
                      >
                        {g.count}
                      </span>
                    </div>
                  ))}
                </div>
                <p className="mt-3 text-center text-xs text-[var(--text-muted)]">
                  总数：3 + 3 + 2 + 4 ={" "}
                  <strong className="text-[var(--text)]">12</strong>
                </p>
              </div>
            </div>

            {/* 结论 */}
            <div className="mt-5 animate-float-in rounded-xl border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 p-5 text-center">
              <div className="text-3xl">💡</div>
              <p className="mt-2 font-bold text-[var(--text)]">
                两种分法的结果相同！
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                按种类分：苹果 3、香蕉 3、葡萄 2、橘子 4
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                按颜色分：红 3、黄 3、紫 2、橙 4
              </p>
              <p className="mt-3 text-base font-bold text-[var(--signal-success)]">
                总数都是 12 个！分类方式不同，但总数不变
              </p>
            </div>

            <div className="mt-5 flex justify-center">
              <button
                onClick={() => setPhase("done")}
                className="rounded-full bg-[var(--accent)] px-8 py-3 font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                我明白了 →
              </button>
            </div>
          </section>
        )}

        {/* ===== 完成 ===== */}
        {phase === "done" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="animate-bounce-soft text-5xl">🏆</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你发现了分类的小秘密：换个分法，总数不会变！
            </p>

            {/* 小结卡片 */}
            <div className="mx-auto mt-6 max-w-sm rounded-xl border-2 border-[var(--primary)] bg-[var(--primary)]/10 p-4">
              <p className="text-center text-sm font-bold text-[var(--text)]">
                分类小发现
              </p>
              <p className="mt-1 text-center text-xs text-[var(--text-secondary)]">
                同一筐水果，按种类或按颜色分，每组的数可能一样多。
                <br />
                不管怎么分，总数都不会变。
              </p>
            </div>

            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <button
                onClick={resetAll}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再练一次
              </button>
              {nextStep ? (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  下一步：{nextStep.label} →
                </Link>
              ) : (
                <Link
                  href="/learn/data"
                  className="rounded-full border border-[var(--border)] px-6 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
                >
                  ← 回到学习路径
                </Link>
              )}
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}
